# TODO: refactor
complex() {
  r=0
  if [ "$1" -gt 0 ]; then r=1; fi
  if [ "$1" -gt 1 ]; then r=1; fi
  if [ "$1" -gt 2 ]; then r=1; fi
  if [ "$1" -gt 3 ]; then r=1; fi
  if [ "$1" -gt 4 ]; then r=1; fi
  if [ "$1" -gt 5 ]; then r=1; fi
  if [ "$1" -gt 6 ]; then r=1; fi
  if [ "$1" -gt 7 ]; then r=1; fi
  if [ "$1" -gt 8 ]; then r=1; fi
  if [ "$1" -gt 9 ]; then r=1; fi
  if [ "$1" -gt 10 ]; then r=1; fi
  if [ "$1" -gt 11 ]; then r=1; fi
  if [ "$1" -gt 12 ]; then r=1; fi
  if [ "$1" -gt 13 ]; then r=1; fi
  if [ "$1" -gt 14 ]; then r=1; fi
  if [ "$1" -gt 15 ]; then r=1; fi
  echo \$r
}
